"use client";
import { useRef } from "react"
import { motion, useScroll, useTransform } from "motion/react"

const footerLinks = [
  {
    title: "Resources",
    links: ["Roadmaps", "Coding PYQs", "Interview Prep", "Tech Blogs", "AI Tools"],
  },
  {
    title: "Community & Career",
    links: ["Startup Directory", "Job Opportunities", "Mentorship"],
  },
  {
    title: "Company",
    links: ["About Us", "Contact", "Support"],
  },
  {
    title: "Legal",
    links: ["Privacy Policy", "Terms of Service", "Refund Policy", "Help Center"],
  },
]

export function Footer() {
  const containerRef = useRef<HTMLDivElement>(null)

  // Track the scroll progress through this specific section
  const { scrollYProgress } = useScroll({
    target: containerRef,
    // "start end" means when top of container hits bottom of viewport
    // "end end" means when bottom of container hits bottom of viewport
    offset: ["start end", "end end"],
  })

  // Map the scroll progress (0 to 1) to height (1px to 100vh)
  const height = useTransform(scrollYProgress, [0, 1], ["1px", "100vh"])

  // Stretch the inner content vertically to match the expanding feeling
  const scaleY = useTransform(scrollYProgress, [0, 1], [0.1, 1])

  // Fade in the content as it expands
  const opacity = useTransform(scrollYProgress, [0, 1], [0, 1])

  return (
    <div ref={containerRef} className="relative h-screen w-full bg-background ">
      <motion.footer
        style={{ height }}
        className="absolute bottom-0 left-0 right-0 flex w-full flex-col overflow-hidden bg-primary text-primary-foreground origin-bottom"
      >
        <motion.div
          style={{ scaleY, opacity }}
          className="flex h-full origin-center flex-col justify-between px-8 py-12 md:px-16 lg:py-20"
        >
          {/* Links Grid Section */}
          <div className="mx-auto grid w-full max-w-7xl grid-cols-2 gap-10 md:grid-cols-4 lg:gap-20">
            {footerLinks.map((group) => (
              <div key={group.title} className="flex flex-col gap-4">
                <h3 className="font-semibold text-primary-foreground/90 md:text-lg">{group.title}</h3>
                <ul className="flex flex-col gap-3">
                  {group.links.map((link) => (
                    <li key={link}>
                      <a href="#" className="text-sm font-medium text-primary-foreground/60 transition-colors hover:text-primary-foreground">
                        {link}
                      </a>
                    </li>
                  ))}
                </ul>
              </div>
            ))}
          </div>

          {/* Bottom Branding Section */}
          <div className="flex w-full flex-col items-center justify-center pt-10">
            <h1 className="font-serif text-[15vw] leading-[0.8] tracking-tight text-primary-foreground">
              Let&apos;s Code
            </h1>
            <p className="mt-4 text-base font-medium text-primary-foreground/80 md:text-xl">
              Build better software, faster.
            </p>
          </div>
        </motion.div>
      </motion.footer>
    </div>
  )
}
